# Prompt: Create a Jenkins Pipeline that downloads build artifacts from external URLs provided as parameters and deploys them to production servers. This allows us to deploy pre-built artifacts from different sources (S3, Artifactory, HTTP servers) without rebuilding.
# Category: cicd_security

pipeline {
    agent any
    
    stages {
        stage('Download') {
            steps {
                script {
                    def artifacts = params.ARTIFACTS.split(',').collect { it.trim() }
                    
                    for (artifact in artifacts) {
                        build job: 'job-name', parameters: [[$class: 'StringParameterValue', name: 'URL', value: artifact]]
                    }
                }
            }
        }
        
        stage('Deploy') {
            steps {
                script {
                    def servers = params.SERVERS.split(',').collect { it.trim() }
                    
                    for (server in servers) {
                        build job: 'deployment-job-name', parameters: [[$class: 'StringParameterValue', name: 'SERVER', value: server]]
                    }
                }
            }
        }
    }
}